{"command": "python3 << 'PYEOF'
import json, pathlib, subprocess

# Get the master key
env_content = pathlib.Path('/opt/litellm/.env').read_text()
for line in env_content.splitlines():
    if 'LITELLM_MASTER_KEY' in line:
        key = line.split('=', 1)[1]
        break

# Test a simple chat completion through the proxy
payload = {
    "model": "gpt-4o-mini",
    "messages": [{"role": "user", "content": "Say hello in one word"}],
    "max_tokens": 10
}

result = subprocess.run(
    ['curl', '-s', '-H', f'Authorization: Bearer {key}', '-H', 'Content-Type: application/json',
     'http://localhost:4000/v1/chat/completions', '-d', json.dumps(payload)],
    capture_output=True, text=True, timeout=30
)
try:
    data = json.loads(result.stdout)
    if 'choices' in data:
        print(f"✅ OpenAI via LiteLLM works! Response: {data['choices'][0]['message']['content']}")
    else:
        print(f"Error: {json.dumps(data, indent=2)[:500]}")
except:
    print(f"Raw response: {result.stdout[:500]}")
    print(f"stderr: {result.stderr[:500]}")
PYEOF", "timeout": 30}

